def main():
    n = read_int()
    sequence = read_ints()

    # Initialize data structures
    subsequences = []
    max_values = []

    for num in sequence:
        # Find the subsequence where num should be inserted
        idx = binary_search(max_values, num)

        if idx == len(max_values):
            # Create a new subsequence if num is larger than all max values
            max_values.append(num)
            subsequences.append([num])
        else:
            # Update the max value and append num to the corresponding subsequence
            max_values[idx] = num
            subsequences[idx].append(num)

    # Print the number of subsequences
    print(len(subsequences))

    # Print the subsequences
    for subsequence in subsequences:
        print(' '.join(map(str, subsequence)))

def binary_search(arr, target):
    left, right = 0, len(arr)
    while left < right:
        mid = (left + right) // 2
        if arr[mid] >= target:
            right = mid
        else:
            left = mid + 1
    return left

