from collections import deque

def build_kmp_table(pattern):
    table = [0] * len(pattern)
    j = 0
    for i in range(1, len(pattern)):
        while j > 0 and pattern[i] != pattern[j]:
            j = table[j - 1]
        if pattern[i] == pattern[j]:
            j += 1
        table[i] = j
    return table

def is_feasible(alphabet, S, T):
    kmp_table_S = build_kmp_table(S)
    kmp_table_T = build_kmp_table(T)
    max_state_S = len(S)
    max_state_T = len(T)

    queue = deque([(0, 0, set())])
    visited = set([(0, 0)])
    while queue:
        state_S, state_T, final_states = queue.popleft()
        if state_S == max_state_S or state_T == max_state_T:
            continue
        for char in alphabet:
            next_state_S = state_S
            next_state_T = state_T
            while next_state_S > 0 and S[next_state_S] != char:
                next_state_S = kmp_table_S[next_state_S - 1]
            if S[next_state_S] == char:
                next_state_S += 1
            while next_state_T > 0 and T[next_state_T] != char:
                next_state_T = kmp_table_T[next_state_T - 1]
            if T[next_state_T] == char:
                next_state_T += 1
            next_final_states = final_states.copy()
            if next_state_S == max_state_S and next_state_T != max_state_T:
                next_final_states.add((next_state_S, next_state_T))
            if next_state_T == max_state_T and next_state_S != max_state_S:
                next_final_states.add((next_state_S, next_state_T))
            if (next_state_S, next_state_T) not in visited:
                visited.add((next_state_S, next_state_T))
                queue.append((next_state_S, next_state_T, next_final_states))
    return len(visited - {(s, s) for s in range(max_state_S + 1)}) == 0

def main():
    K = int(input())
    for _ in range(K):
        alphabet, S, T = input().split()
        print(1 if is_feasible(alphabet, S, T) else 0)

